sql:
SELECT party, COUNT(*) AS party_member_count
FROM congressional_members
GROUP BY party;

SELECT firstname, lastname
FROM congressional_members
WHERE chamber = 'Senate';

SELECT COUNT(*) 
FROM congressional_members 
WHERE congress = 80;

SELECT congress_number, SUM(total_members) AS total_member_count
FROM congresses
GROUP BY congress_number;

SELECT firstname, middlename, lastname, age
FROM congressional_members
WHERE age = (SELECT MAX(age) FROM congressional_members);

external_knowledge:
- 'D' refers to the Democratic party affiliation; 
- 'Senate' refers to the chamber in the US Congress; 
- The query is based on the assumption that the age listed is the age of the member when their term started.

sql:
SELECT firstname || ' ' || middlename || ' ' || lastname AS full_name
FROM congressional_members
ORDER BY age ASC;

SELECT lastname
FROM congressional_members
WHERE chamber = 'Senate' AND party = 'D';

SELECT firstname, lastname, party 
FROM congressional_members 
WHERE congress = 80;

SELECT AVG(age) AS average_age
FROM congressional_members
WHERE congress = 80 AND state = 'NC';

external_knowledge:
; Congressional members are individuals elected to serve in the U.S. Congress, which is the legislative branch of the federal government; 
; The 'Civil Rights' legislative focus refers to congresses that have addressed issues related to civil rights, such as voting rights, equality, and social justice; 
; The 'South' region refers to states located in the Southern United States.

sql:
SELECT firstname, lastname
FROM congressional_members
WHERE age = (SELECT MIN(age) FROM congressional_members);

SELECT AVG(age) AS average_age
FROM congressional_members
WHERE chamber = 'House';
